/**
 * One-time migration — copies party_citizens entries into the main citizens
 * table, preserving kiosk-assigned citizen_number / tomoland_id. Run after
 * the event.
 *
 * Usage:
 *   node scripts/migrate-party-to-main.mjs
 *
 * Preferred for a fresh migration: scripts/migrate-party-to-main.sql in
 * Supabase SQL Editor (single transaction, no identity-column friction).
 *
 * If party guests were already migrated with fresh directory numbers, run
 * scripts/fix-party-citizen-numbers.sql to restore kiosk numbers.
 *
 * This script requires citizen_number to be GENERATED BY DEFAULT. If inserts
 * fail, use migrate-party-to-main.sql instead.
 */

import { createClient } from '@supabase/supabase-js'
import { readFileSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))

const envPath = join(__dirname, '..', '.env.local')
const envContent = readFileSync(envPath, 'utf8')
for (const line of envContent.split('\n')) {
  const trimmed = line.trim()
  if (!trimmed || trimmed.startsWith('#')) continue
  const [key, ...rest] = trimmed.split('=')
  if (key && rest.length) process.env[key] = rest.join('=')
}

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL,
  process.env.SUPABASE_SERVICE_ROLE_KEY,
)

async function main() {
  console.log('Fetching party_citizens...\n')

  const { data: party, error: fetchError } = await supabase
    .from('party_citizens')
    .select(
      'citizen_number, tomoland_id, name, relation_to_tomo, place_of_issue, photo_url, created_at',
    )
    .order('created_at', { ascending: true })

  if (fetchError) {
    console.error('Failed to fetch party_citizens:', fetchError.message)
    process.exit(1)
  }

  console.log(`Found ${party.length} party entries. Migrating to citizens...\n`)

  let inserted = 0
  let failed = 0

  for (const guest of party) {
    try {
      if (guest.photo_url) {
        const { data: existing } = await supabase
          .from('citizens')
          .select('id, tomoland_id')
          .eq('photo_url', guest.photo_url)
          .maybeSingle()

        if (existing) {
          console.log(`  ⏭️  ${existing.tomoland_id} — ${guest.name} (already in directory)`)
          continue
        }
      }

      const { data, error } = await supabase
        .from('citizens')
        .insert({
          citizen_number: guest.citizen_number,
          name: guest.name,
          relation_to_tomo: guest.relation_to_tomo,
          place_of_issue: guest.place_of_issue,
          photo_url: guest.photo_url,
        })
        .select()
        .single()

      if (error) throw new Error(error.message)
      const idOk = data.tomoland_id === guest.tomoland_id
      console.log(
        `  ${idOk ? '✅' : '⚠️'} ${data.tomoland_id} — ${guest.name}${idOk ? '' : ` (kiosk was ${guest.tomoland_id})`}`,
      )
      inserted++
    } catch (err) {
      console.error(`  ❌ Failed ${guest.name}: ${err.message}`)
      failed++
    }

    await new Promise((r) => setTimeout(r, 80))
  }

  console.log(`\n🏁 Done: ${inserted} migrated, ${failed} failed`)
}

main().catch(console.error)
